import{_ as a,o as r,c as l,a4 as i}from"./chunks/framework.CwFacL3z.js";const c=JSON.parse('{"title":"字源形碼","description":"","frontmatter":{"outline":"deep","title":"字源形碼"},"headers":[],"relativePath":"tw/xingma/index.md","filePath":"tw/xingma/index.md","lastUpdated":1773588811000}'),o={name:"tw/xingma/index.md"};function n(e,t,s,h,d,g){return r(),l("div",null,[...t[0]||(t[0]=[i(`<h1 id="字源形碼" tabindex="-1">字源形碼 <a class="header-anchor" href="#字源形碼" aria-label="Permalink to &quot;字源形碼&quot;">​</a></h1><p>字源形碼是一款入門簡單且性能強大的形碼輸入法，專為現代用戶設計。</p><h2 id="🎯-設計理念" tabindex="-1">🎯 設計理念 <a class="header-anchor" href="#🎯-設計理念" aria-label="Permalink to &quot;🎯 設計理念&quot;">​</a></h2><p>字源形碼基於漢字字源和結構規律，採用科學的拆分方法，讓輸入更加自然高效。</p><h3 id="核心特點" tabindex="-1">核心特點 <a class="header-anchor" href="#核心特點" aria-label="Permalink to &quot;核心特點&quot;">​</a></h3><ul><li><strong>簡單易學</strong>：僅需20個核心字根，30分鐘即可上手</li><li><strong>科學拆字</strong>：基於漢字自然結構，符合直覺</li><li><strong>高效輸入</strong>：四碼定長，低重碼率，打字流暢</li><li><strong>大字集支持</strong>：支持10萬漢字，覆蓋日常使用需求</li></ul><h2 id="🔤-字根系統" tabindex="-1">🔤 字根系統 <a class="header-anchor" href="#🔤-字根系統" aria-label="Permalink to &quot;🔤 字根系統&quot;">​</a></h2><h3 id="字根分佈" tabindex="-1">字根分佈 <a class="header-anchor" href="#字根分佈" aria-label="Permalink to &quot;字根分佈&quot;">​</a></h3><p>字源形碼的20個核心字根科學地分佈在26個鍵位上：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q W E R T Y U I O P</span></span>
<span class="line"><span> A S D F G H J K L</span></span>
<span class="line"><span>  Z X C V B N M</span></span></code></pre></div><h3 id="字根分類" tabindex="-1">字根分類 <a class="header-anchor" href="#字根分類" aria-label="Permalink to &quot;字根分類&quot;">​</a></h3><h4 id="基礎字根" tabindex="-1">基礎字根 <a class="header-anchor" href="#基礎字根" aria-label="Permalink to &quot;基礎字根&quot;">​</a></h4><ul><li><strong>橫豅點撇</strong>：基本筆畫字根</li><li><strong>偏旁部首</strong>：常見偏旁部首</li><li><strong>獨體字</strong>：常用獨體字</li></ul><h4 id="組合字根" tabindex="-1">組合字根 <a class="header-anchor" href="#組合字根" aria-label="Permalink to &quot;組合字根&quot;">​</a></h4><ul><li><strong>形近字根</strong>：字形相似的字根</li><li><strong>音近字根</strong>：讀音相近的字根</li><li><strong>義近字根</strong>：意義相關的字根</li></ul><h2 id="📖-編碼規則" tabindex="-1">📖 編碼規則 <a class="header-anchor" href="#📖-編碼規則" aria-label="Permalink to &quot;📖 編碼規則&quot;">​</a></h2><h3 id="基本原則" tabindex="-1">基本原則 <a class="header-anchor" href="#基本原則" aria-label="Permalink to &quot;基本原則&quot;">​</a></h3><ol><li><strong>取大優先</strong>：優先取最大字根</li><li><strong>順序優先</strong>：按書寫順序取碼</li><li><strong>結構優先</strong>：考慮漢字結構特點</li><li><strong>頻率優先</strong>：常用字優先考慮</li></ol><h3 id="編碼長度" tabindex="-1">編碼長度 <a class="header-anchor" href="#編碼長度" aria-label="Permalink to &quot;編碼長度&quot;">​</a></h3><ul><li><strong>一碼字</strong>：超高頻常用字</li><li><strong>二碼字</strong>：高頻常用字</li><li><strong>三碼字</strong>：一般常用字</li><li><strong>四碼字</strong>：複雜字和低頻字</li></ul><h3 id="特殊規則" tabindex="-1">特殊規則 <a class="header-anchor" href="#特殊規則" aria-label="Permalink to &quot;特殊規則&quot;">​</a></h3><ul><li><strong>簡碼處理</strong>：常用字簡化編碼</li><li><strong>重碼處理</strong>：智能重碼選擇</li><li><strong>容錯處理</strong>：允許一定容錯範圍</li></ul><h2 id="🎮-學習方法" tabindex="-1">🎮 學習方法 <a class="header-anchor" href="#🎮-學習方法" aria-label="Permalink to &quot;🎮 學習方法&quot;">​</a></h2><h3 id="初學階段" tabindex="-1">初學階段 <a class="header-anchor" href="#初學階段" aria-label="Permalink to &quot;初學階段&quot;">​</a></h3><ol><li><strong>熟悉字根</strong>：掌握20個核心字根</li><li><strong>理解規則</strong>：理解基本編碼規則</li><li><strong>順序練習</strong>：按順序練習所有字根</li><li><strong>鞏固記憶</strong>：通過重複練習鞏固</li></ol><h3 id="進階階段" tabindex="-1">進階階段 <a class="header-anchor" href="#進階階段" aria-label="Permalink to &quot;進階階段&quot;">​</a></h3><ol><li><strong>隨機練習</strong>：隨機抽測字根記憶</li><li><strong>常用字根</strong>：重點練習高頻字根</li><li><strong>錯題複習</strong>：專門練習錯誤字根</li><li><strong>實戰應用</strong>：在日常使用中練習</li></ol><h3 id="熟練階段" tabindex="-1">熟練階段 <a class="header-anchor" href="#熟練階段" aria-label="Permalink to &quot;熟練階段&quot;">​</a></h3><ol><li><strong>速度提升</strong>：提升打字速度和準確性</li><li><strong>盲打訓練</strong>：實現不看鍵盤輸入</li><li><strong>詞組輸入</strong>：學習詞組和短語輸入</li><li><strong>高級技巧</strong>：掌握各種輸入技巧</li></ol><h2 id="📊-性能指標" tabindex="-1">📊 性能指標 <a class="header-anchor" href="#📊-性能指標" aria-label="Permalink to &quot;📊 性能指標&quot;">​</a></h2><h3 id="輸入效率" tabindex="-1">輸入效率 <a class="header-anchor" href="#輸入效率" aria-label="Permalink to &quot;輸入效率&quot;">​</a></h3><ul><li><strong>平均碼長</strong>：2.8碼/字</li><li><strong>重碼率</strong>：低於1%</li><li><strong>首選命中率</strong>：高於95%</li><li><strong>輸入速度</strong>：可達100字/分鐘</li></ul><h3 id="學習效率" tabindex="-1">學習效率 <a class="header-anchor" href="#學習效率" aria-label="Permalink to &quot;學習效率&quot;">​</a></h3><ul><li><strong>入門時間</strong>：30分鐘掌握字根</li><li><strong>熟練時間</strong>：1-2週達到實用水平</li><li><strong>精通時間</strong>：1個月達到高效水平</li><li><strong>記憶難度</strong>：相比五筆降低70%</li></ul><h2 id="🔧-技術特點" tabindex="-1">🔧 技術特點 <a class="header-anchor" href="#🔧-技術特點" aria-label="Permalink to &quot;🔧 技術特點&quot;">​</a></h2><h3 id="字集支持" tabindex="-1">字集支持 <a class="header-anchor" href="#字集支持" aria-label="Permalink to &quot;字集支持&quot;">​</a></h3><ul><li><strong>GB2312</strong>：基礎漢字字符集</li><li><strong>GBK</strong>：擴展漢字字符集</li><li><strong>Big5</strong>：繁體中文字符集</li><li><strong>CJK</strong>：中日韓統一字符集</li></ul><h3 id="平台支持" tabindex="-1">平台支持 <a class="header-anchor" href="#平台支持" aria-label="Permalink to &quot;平台支持&quot;">​</a></h3><ul><li><strong>Windows</strong>：全版本Windows支持</li><li><strong>macOS</strong>：Intel和Apple Silicon支持</li><li><strong>Linux</strong>：主流發行版支持</li><li><strong>移動端</strong>：Android和iOS支持</li></ul><h2 id="🌟-優勢對比" tabindex="-1">🌟 優勢對比 <a class="header-anchor" href="#🌟-優勢對比" aria-label="Permalink to &quot;🌟 優勢對比&quot;">​</a></h2><h3 id="與拼音輸入法對比" tabindex="-1">與拼音輸入法對比 <a class="header-anchor" href="#與拼音輸入法對比" aria-label="Permalink to &quot;與拼音輸入法對比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>字源形碼</th><th>拼音輸入法</th></tr></thead><tbody><tr><td>輸入效率</td><td>高</td><td>中</td></tr><tr><td>學習難度</td><td>低</td><td>極低</td></tr><tr><td>重碼率</td><td>低</td><td>高</td></tr><tr><td>準確性</td><td>高</td><td>中</td></tr><tr><td>適用場景</td><td>專業輸入</td><td>日常交流</td></tr></tbody></table><h3 id="與五筆輸入法對比" tabindex="-1">與五筆輸入法對比 <a class="header-anchor" href="#與五筆輸入法對比" aria-label="Permalink to &quot;與五筆輸入法對比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>字源形碼</th><th>五筆輸入法</th></tr></thead><tbody><tr><td>字根數量</td><td>20個</td><td>130+個</td></tr><tr><td>學習難度</td><td>低</td><td>高</td></tr><tr><td>入門時間</td><td>30分鐘</td><td>數小時</td></tr><tr><td>記憶難度</td><td>低</td><td>高</td></tr><tr><td>現代化</td><td>高</td><td>中</td></tr></tbody></table><h2 id="🚀-發展歷程" tabindex="-1">🚀 發展歷程 <a class="header-anchor" href="#🚀-發展歷程" aria-label="Permalink to &quot;🚀 發展歷程&quot;">​</a></h2><h3 id="誕生背景" tabindex="-1">誕生背景 <a class="header-anchor" href="#誕生背景" aria-label="Permalink to &quot;誕生背景&quot;">​</a></h3><p>字源形碼誕生於現代輸入法發展的關鍵時期，旨在解決傳統形碼學習難度大、拼音輸入效率低的問題。</p><h3 id="發展階段" tabindex="-1">發展階段 <a class="header-anchor" href="#發展階段" aria-label="Permalink to &quot;發展階段&quot;">​</a></h3><ol><li><strong>研究階段</strong>：深入研究漢字結構和輸入法理論</li><li><strong>設計階段</strong>：科學設計字根系統和編碼規則</li><li><strong>開發階段</strong>：開發輸入法引擎和用戶界面</li><li><strong>優化階段</strong>：根據用戶反饋持續優化改進</li></ol><h3 id="未來規劃" tabindex="-1">未來規劃 <a class="header-anchor" href="#未來規劃" aria-label="Permalink to &quot;未來規劃&quot;">​</a></h3><ul><li><strong>智能化</strong>：結合AI技術提升輸入體驗</li><li><strong>個性化</strong>：支持個性化定制和適應</li><li><strong>雲端化</strong>：支持雲端同步和備份</li><li><strong>國際化</strong>：支持多語言和跨平台</li></ul><h2 id="🤝-社區支持" tabindex="-1">🤝 社區支持 <a class="header-anchor" href="#🤝-社區支持" aria-label="Permalink to &quot;🤝 社區支持&quot;">​</a></h2><h3 id="用戶社群" tabindex="-1">用戶社群 <a class="header-anchor" href="#用戶社群" aria-label="Permalink to &quot;用戶社群&quot;">​</a></h3><ul><li><strong>QQ群</strong>：活躍的用戶交流群</li><li><strong>論壇</strong>：專門的技術討論論壇</li><li><strong>社交媒體</strong>：多平台社交媒體帳號</li><li><strong>線下活動</strong>：定期舉辦線下交流活動</li></ul><h3 id="技術支持" tabindex="-1">技術支持 <a class="header-anchor" href="#技術支持" aria-label="Permalink to &quot;技術支持&quot;">​</a></h3><ul><li><strong>文檔中心</strong>：詳細的使用文檔和教程</li><li><strong>視頻教程</strong>：系列視頻教程指導</li><li><strong>在線客服</strong>：專業的在線技術支持</li><li><strong>用戶手冊</strong>：完整的用戶使用手冊</li></ul><h2 id="📚-相關資源" tabindex="-1">📚 相關資源 <a class="header-anchor" href="#📚-相關資源" aria-label="Permalink to &quot;📚 相關資源&quot;">​</a></h2><h3 id="學習資料" tabindex="-1">學習資料 <a class="header-anchor" href="#學習資料" aria-label="Permalink to &quot;學習資料&quot;">​</a></h3><ul><li><a href="/introduction">快速入門</a> - 新手入門指南</li><li><a href="/route">學習路線</a> - 系統學習路線</li><li><a href="/practice/">練習工具</a> - 在線練習工具</li><li><a href="/faq">常見問題</a> - 常見問題解答</li></ul><h3 id="下載資源" tabindex="-1">下載資源 <a class="header-anchor" href="#下載資源" aria-label="Permalink to &quot;下載資源&quot;">​</a></h3><ul><li><a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">輸入法下載</a> - 官方下載地址</li><li><a href="/fonts">字體資源</a> - 相關字體下載</li><li><a href="/config">配置文件</a> - 配置文件下載</li><li><a href="/dev">開發工具</a> - 開發者工具</li></ul><hr><p>字源形碼，讓輸入變得簡單高效！</p>`,63)])])}const b=a(o,[["render",n]]);export{c as __pageData,b as default};
